select id, attended_time, unit_name, unit_id, chief_duty_name, chief_duty_id, chief_duty_zhiwu, telephone_bg, telephone_ss, chief_duty_phone, duty_offier_name, duty_offier_id, duty_offier_zw, duty_offier_phone, duty_phone, duty_gangwei from
bdgl_grassduty g
left join sys_dept t
on g.unit_id=t.dept_id


        and (g.unit_id=#{unitId} or find_in_set(#{unitId}, t.ancestors))

     and g.attended_time = #{attendedTime}
     and g.unit_name like concat('%', #{unitName}, '%')
     and g.chief_duty_name like concat('%', #{chiefDutyName}, '%')
     and g.chief_duty_id = #{chiefDutyId}
     and g.chief_duty_zhiwu = #{chiefDutyZhiwu}
     and g.telephone_bg = #{telephoneBg}
     and g.telephone_ss = #{telephoneSs}
     and g.chief_duty_phone = #{chiefDutyPhone}
     and g.duty_offier_name like concat('%', #{dutyOffierName}, '%')
     and g.duty_offier_id = #{dutyOffierId}
     and g.duty_offier_zw = #{dutyOffierZw}
     and g.duty_offier_phone = #{dutyOffierPhone}
     and g.duty_phone = #{dutyPhone}
     and g.duty_gangwei = #{dutyGangwei}

order by g.id desc

